import{_ as i,c as a,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"プラットフォームと統合: マルチモデル AI 設定 | oh-my-opencode","description":"複数の AI プラットフォーム（Anthropic、OpenAI、Google、Copilot）の設定と管理を学び、自動フェイルバックメカニズムとインテリジェントなモデル選択をマスターします。","frontmatter":{"title":"プラットフォームと統合: マルチモデル AI 設定 | oh-my-opencode","sidebarTitle":"AI アカウントを接続","subtitle":"プラットフォームと統合: マルチモデル AI 設定","description":"複数の AI プラットフォーム（Anthropic、OpenAI、Google、Copilot）の設定と管理を学び、自動フェイルバックメカニズムとインテリジェントなモデル選択をマスターします。","order":40},"headers":[],"relativePath":"ja/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"ja/code-yeongyu/oh-my-opencode/platforms/index.md"}'),r={name:"ja/code-yeongyu/oh-my-opencode/platforms/index.md"};function s(t,e,n,d,p,h){return o(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="プラットフォームと統合" tabindex="-1">プラットフォームと統合 <a class="header-anchor" href="#プラットフォームと統合" aria-label="Permalink to &quot;プラットフォームと統合&quot;">​</a></h1><p>本章では、複数の AI Provider（Anthropic、OpenAI、Google、GitHub Copilot など）の設定と管理方法、および oh-my-opencode のマルチモデル自動フェイルバックメカニズムについて説明します。</p><p>本章を学ぶことで、タスクタイプと利用可能なモデルに基づいてシステムが最適な AI モデルをインテリジェントに選択する方法をマスターし、効率的で信頼性の高いマルチモデルオーケストレーションワークフローを構築できるようになります。</p><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><p>本章は 2 つのパートに分かれています：</p><h3 id="_1-provider-設定" tabindex="-1">1. <a href="./provider-setup/">Provider 設定</a> <a class="header-anchor" href="#_1-provider-設定" aria-label="Permalink to &quot;1. [Provider 設定](provider-setup/)&quot;">​</a></h3><p>複数の AI Provider の設定方法を学びます：</p><ul><li>Anthropic Claude（メインオーケストレーターの第一候補）</li><li>OpenAI ChatGPT（アーキテクチャレビュー専用）</li><li>Google Gemini（フロントエンドとメディア分析）</li><li>GitHub Copilot（バックアップ Provider）</li><li>Z.ai Coding Plan と OpenCode Zen（オプションサービス）</li></ul><p><strong>学習後できること</strong>：</p><ul><li>✅ 6 つの主要な AI Provider を設定する</li><li>✅ インタラクティブなインストーラーで素早く設定する</li><li>✅ 各エージェントに最適なモデルを指定する</li><li>✅ <code>doctor</code> コマンドを使用して設定問題を診断する</li></ul><p><strong>所要時間</strong>：25-30 分</p><h3 id="_2-マルチモデル戦略" tabindex="-1">2. <a href="./model-resolution/">マルチモデル戦略</a> <a class="header-anchor" href="#_2-マルチモデル戦略" aria-label="Permalink to &quot;2. [マルチモデル戦略](model-resolution/)&quot;">​</a></h3><p>モデル解決システムの 3 段階優先度メカニズムを深く理解します：</p><ul><li>ユーザーオーバーライド（正確な制御）</li><li>Provider フェイルバック（自動フォールトトレランス）</li><li>システムデフォルト（フォールバックソリューション）</li></ul><p><strong>学習後できること</strong>：</p><ul><li>✅ モデル解決の完全なワークフローを理解する</li><li>✅ タスク要件に基づいて手動でモデルを指定する</li><li>✅ Provider フェイルバックを活用してシステムの堅牢性を向上させる</li><li>✅ モデル解決の問題を診断・解決する</li></ul><p><strong>所要時間</strong>：30-35 分</p><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><p>本章は以下の順序で学習することをお勧めします：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[インストール完了] --&gt; B[Provider 設定]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[マルチモデル戦略]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[高度な機能]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>なぜこの順序なのか？</strong></p><ol><li><strong>まず設定、次に理解</strong>：まず各 Provider の設定方法を学び、その後背後にある解決メカニズムを理解する</li><li><strong>シンプルから複雑へ</strong>：Provider 設定は基本操作、マルチモデル戦略は高度な概念</li><li><strong>実践で理論を検証</strong>：Provider を設定した後、<code>doctor</code> コマンドを使用してマルチモデル戦略の効果を検証できる</li></ol><div class="tip custom-block"><p class="custom-block-title">クイックスタートパス</p><p>すぐに始めたい場合は、<a href="./provider-setup/">Provider 設定</a> のステップ 1-4（基本 Provider の設定）を完了し、他の内容は必要に応じて後で学習できます。</p></div><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>本章を学習する前に、以下を確認してください：</p><ul><li>✅ <a href="./../installation/">インストールと初期設定</a> を完了している</li><li>✅ OpenCode をインストールしている（バージョン &gt;= 1.0.150）</li><li>✅ 基本的な JSON/JSONC 設定ファイル形式を理解している</li><li>✅ 少なくとも 1 つの AI Provider のアカウントサブスクリプションを持っている（Anthropic Claude を推奨）</li></ul><div class="warning custom-block"><p class="custom-block-title">Provider アカウントがない場合怎么办？</p><p>Provider に実際に接続せずに、まず設定手順を学ぶことができます。システムは OpenCode のデフォルトモデルをフォールバックとして使用します。</p></div><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><details><summary><strong>すべての Provider を設定する必要がありますか？</strong></summary><p>いいえ。最も頻繁に使用する Provider（例：Anthropic Claude のみ）だけを設定できます。oh-my-opencode の Provider フェイルバックメカニズムは、利用可能な Provider を自動的に使用します。</p><p>ただし、マルチモデルオーケストレーションの利点を最大限に活用したい場合は、少なくとも 2-3 つの Provider を設定することをお勧めします。これにより、システムはタスクタイプに基づいて最適なモデルを自動的に選択できます。</p></details><details><summary><strong>Provider 設定とモデル解決の違いは何ですか？</strong></summary><ul><li><strong>Provider 設定</strong>：「インストールステップ」、システムに利用可能な AI サービスを伝える</li><li><strong>モデル解決</strong>：「意思決定ロジック」、システムが各エージェントに対してどの Provider を使用するかを選択する方法</li></ul><p>比喩：Provider 設定は「チームメンバーの採用」、モデル解決は「タスクの割り当て」。</p></details><details><summary><strong>設定はいつでも変更できますか？</strong></summary><p>設定ファイルはいつでも変更できます：</p><ul><li>ユーザー設定：<code>~/.config/opencode/oh-my-opencode.json</code></li><li>プロジェクト設定：<code>.opencode/oh-my-opencode.json</code></li></ul><p>変更後、次回エージェントを使用するときに自動的に反映されます。Provider 認証を変更した場合は、<code>opencode auth login</code> を実行して再認証する必要があります。</p></details><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章を完了した後、以下のことができます：</p><h3 id="推奨パス-ai-エージェントチームを学ぶ" tabindex="-1">推奨パス：AI エージェントチームを学ぶ <a class="header-anchor" href="#推奨パス-ai-エージェントチームを学ぶ" aria-label="Permalink to &quot;推奨パス：AI エージェントチームを学ぶ&quot;">​</a></h3><p><a href="./../../advanced/ai-agents-overview/">AI エージェントチーム：10 人のエキスパート紹介</a> を続けて学び、専門的なタスクに異なるエージェントを使用する方法を理解します。</p><h3 id="高度なパス-深度カスタマイズ" tabindex="-1">高度なパス：深度カスタマイズ <a class="header-anchor" href="#高度なパス-深度カスタマイズ" aria-label="Permalink to &quot;高度なパス：深度カスタマイズ&quot;">​</a></h3><p>基本設定に既に慣れている場合は、<a href="./../../advanced/advanced-configuration/">設定深度カスタマイズ：エージェントと権限管理</a> にジャンプして、以下を学習できます：</p><ul><li>エージェントのプロンプトをカスタマイズする方法</li><li>エージェントの権限とアクセススコープを設定する方法</li><li>カスタムエージェントとカテゴリを作成する方法</li></ul><h3 id="実践パス-prometheus-プランニングを使用する" tabindex="-1">実践パス：Prometheus プランニングを使用する <a class="header-anchor" href="#実践パス-prometheus-プランニングを使用する" aria-label="Permalink to &quot;実践パス：Prometheus プランニングを使用する&quot;">​</a></h3><p><a href="./../../advanced/prometheus-planning/">Prometheus プランニング：インタビュー形式の要件収集</a> の使用を開始し、実際のエージェント協力を通じてマルチモデルオーケストレーションの威力を体験します。</p><hr><p><strong>始めましょう</strong>：<a href="./provider-setup/">Provider 設定</a> からマルチモデルオーケストレーションの旅を始めましょう！</p>`,42)])])}const m=i(r,[["render",s]]);export{u as __pageData,m as default};
